  1→import { createContext, useContext, useEffect, useReducer } from 'react';
  2→import { TOOLS } from '@/editor/tools';
  3→import { DEFAULT_ZOOM } from '@/domain/defaults';
  4→
  5→const EditorContext = createContext(null);
  6→
  7→function normalizeViewMode(viewMode) {
  8→  if (viewMode === 'elevation_side') return 'elevation_left';
  9→  return viewMode;
 10→}
 11→
 12→function getInitialModelViewport() {
 13→  return { panX: 400, panY: 300, zoom: DEFAULT_ZOOM };
 14→}
 15→
 16→function getInitialSheetViewport() {
 17→  return { panX: 120, panY: 80, zoom: 2 };
 18→}
 19→
 20→function clearSelectionState(state) {
 21→  return {
 22→    ...state,
 23→    selectedId: null,
 24→    selectedType: null,
 25→    regionSelection: null,
 26→    pastePreview: { active: false, point: null },
 27→  };
 28→}
 29→
 30→function editorReducer(state, action) {
 31→  switch (action.type) {
 32→    case 'SET_MODEL_TARGET':
 33→      return {
 34→        ...clearSelectionState(state),
 35→        workspaceMode: 'model',
 36→        modelTarget: action.modelTarget,
 37→        activeTool: TOOLS.SELECT,
 38→        toolState: {},
 39→        statusMessage: null,
 40→      };
 41→
 42→    case 'SET_TOOL':
 43→      return {
 44→        ...clearSelectionState(state),
 45→        activeTool: action.tool,
 46→        toolState: {},
 47→        statusMessage: null,
 48→      };
 49→
 50→    case 'SET_VIEW_MODE':
 51→      return {
 52→        ...clearSelectionState(state),
 53→        workspaceMode: 'model',
 54→        viewMode: normalizeViewMode(action.viewMode),
 55→        activeSectionCutId: action.sectionCutId ?? state.activeSectionCutId,
 56→        viewport: { ...state.modelViewport },
 57→        toolState: {},
 58→        statusMessage: null,
 59→      };
 60→
 61→    case 'SET_WORKSPACE_MODE':
 62→      return {
 63→        ...clearSelectionState(state),
 64→        workspaceMode: action.workspaceMode,
 65→        viewport: action.workspaceMode === 'sheet'
 66→          ? { ...state.sheetViewport }
 67→          : { ...state.modelViewport },
 68→        toolState: {},
 69→        statusMessage: null,
 70→      };
 71→
 72→    case 'SET_ACTIVE_SHEET':
 73→      return {
 74→        ...clearSelectionState(state),
 75→        activeSheetId: action.sheetId,
 76→        statusMessage: null,
 77→      };
 78→
 79→    case 'SELECT_OBJECT':
 80→      return {
 81→        ...clearSelectionState(state),
 82→        selectedId: action.id,
 83→        selectedType: action.objectType,
 84→      };
 85→
 86→    case 'DESELECT':
 87→      return clearSelectionState(state);
 88→
 89→    case 'SET_REGION_SELECTION':
 90→      return {
 91→        ...clearSelectionState(state),
 92→        regionSelection: action.selection && action.bounds
 93→          ? {
 94→              bounds: action.bounds,
 95→              selection: action.selection,
 96→              objectCount: Object.values(action.selection).reduce((count, ids) => count + (ids?.length || 0), 0),
 97→            }
 98→          : null,
 99→      };
100→
101→    case 'UPDATE_TOOL_STATE':
102→      return {
103→        ...state,
104→        toolState: { ...state.toolState, ...action.payload },
105→      };
106→
107→    case 'SET_VIEWPORT':
108→      return {
109→        ...state,
110→        modelViewport: state.workspaceMode === 'model' ? { ...action.viewport } : state.modelViewport,
111→        sheetViewport: state.workspaceMode === 'sheet' ? { ...action.viewport } : state.sheetViewport,
112→        viewport: { ...action.viewport },
113→      };
114→
115→    case 'PAN':
116→      return {
117→        ...state,
118→        modelViewport: state.workspaceMode === 'model'
119→          ? {
120→              ...state.modelViewport,
121→              panX: state.modelViewport.panX + action.dx,
122→              panY: state.modelViewport.panY + action.dy,
123→            }
124→          : state.modelViewport,
125→        sheetViewport: state.workspaceMode === 'sheet'
126→          ? {
127→              ...state.sheetViewport,
128→              panX: state.sheetViewport.panX + action.dx,
129→              panY: state.sheetViewport.panY + action.dy,
130→            }
131→          : state.sheetViewport,
132→        viewport: {
133→          ...state.viewport,
134→          panX: state.viewport.panX + action.dx,
135→          panY: state.viewport.panY + action.dy,
136→        },
137→      };
138→
139→    case 'ZOOM': {
140→      const { zoom, panX, panY } = action;
141→      return {
142→        ...state,
143→        modelViewport: state.workspaceMode === 'model' ? { zoom, panX, panY } : state.modelViewport,
144→        sheetViewport: state.workspaceMode === 'sheet' ? { zoom, panX, panY } : state.sheetViewport,
145→        viewport: { zoom, panX, panY },
146→      };
147→    }
148→
149→    case 'TOGGLE_GRID':
150→      return { ...state, showGrid: !state.showGrid };
151→
152→    case 'TOGGLE_SNAP':
153→      return { ...state, snapEnabled: !state.snapEnabled };
154→
155→    case 'SET_ACTIVE_FLOOR':
156→      return {
157→        ...clearSelectionState(state),
158→        activeFloorId: action.floorId,
159→        toolState: {},
160→        statusMessage: null,
161→      };
162→
163→    case 'SET_STATUS_MESSAGE':
164→      return { ...state, statusMessage: action.message };
165→
166→    case 'CLEAR_STATUS_MESSAGE':
167→      if (!state.statusMessage) return state;
168→      return { ...state, statusMessage: null };
169→
170→    case 'START_PASTE_PREVIEW':
171→      return {
172→        ...state,
173→        selectedId: null,
174→        selectedType: null,
175→        regionSelection: null,
176→        pastePreview: {
177→          active: true,
178→          point: action.point ?? null,
179→        },
180→      };
181→
182→    case 'UPDATE_PASTE_PREVIEW':
183→      if (!state.pastePreview?.active) return state;
184→      return {
185→        ...state,
186→        pastePreview: {
187→          active: true,
188→          point: action.point,
189→        },
190→      };
191→
192→    case 'CANCEL_PASTE_PREVIEW':
193→      if (!state.pastePreview?.active) return state;
194→      return {
195→        ...state,
196→        pastePreview: {
197→          active: false,
198→          point: null,
199→        },
200→      };
201→
202→    case 'TOGGLE_MAXIMIZE_PANEL':
203→      return {
204→        ...state,
205→        maximizedPanel: state.maximizedPanel === action.panel ? null : action.panel,
206→      };
207→
208→    case 'SET_ACTIVE_PHASE':
209→      return { ...state, activePhaseId: action.phaseId };
210→
211→    case 'SET_PHASE_VIEW_MODE':
212→      return { ...state, phaseViewMode: action.mode };
213→
214→    default:
215→      return state;
216→  }
217→}
